export function nextGeneration(cells: Cell[]): Cell[] {
  const liveKeys = new Set(cells.map(keyOf));
  const result: Cell[] = [];
  for (const [key, { cell, count }] of countNeighbors(cells)) {
    if (survives(liveKeys.has(key), count)) result.push(cell);
  }
  return result;
}

